#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int a, b, n;
        scanf("%d %d %d", &a, &b, &n);
        int count = 0;
        for (int i = 0; i < n; i++) {
            int x;
            scanf("%d", &x);
            if (x % a == 0 || x % b == 0) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

